class Solution {
    public String discountPrices(String sentence, int discount) {
        String[] words = sentence.split(" ");
        StringBuilder result = new StringBuilder();
        for (String word : words) {
            if (word.startsWith("$") && word.length() > 1 && word.substring(1).matches("\\d+")) {
                double price = Double.parseDouble(word.substring(1));
                double discountAmount = (price / 100) * discount;
                double discountedPrice = price - discountAmount;
                String formattedPrice = String.format("%.2f", discountedPrice);
                result.append("$").append(formattedPrice).append(" ");
            } else {
                result.append(word).append(" ");
            }
        }
        return result.toString().trim();
    }
}
```

